 1	import * as React from 'react';
 2	import { serverConfig } from 'config';
 3	import { kialiStyle } from 'styles/StyleUtils';
 4	import { Dropdown, DropdownItem, DropdownList, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 5	
 6	type FindKind = 'find' | 'hide';
 7	
 8	type MeshFindOptionsProps = {
 9	  kind: FindKind;
10	  onSelect: (expression: string) => void;
11	};
12	
13	const menuToggleStyle = kialiStyle({
14	  paddingRight: 0,
15	  $nest: {
16	    '& .pf-v6-c-menu-toggle__controls': {
17	      paddingLeft: 0
18	    }
19	  }
20	});
21	
22	export const MeshFindOptions: React.FC<MeshFindOptionsProps> = (props: MeshFindOptionsProps) => {
23	  const { kind, onSelect } = props;
24	  const [isOpen, setIsOpen] = React.useState<boolean>(false);
25	  const [options, setOptions] = React.useState<React.ReactNode[]>([]);
26	
27	  React.useEffect(() => {
28	    const getOptionItems = (kind: FindKind): React.ReactFragment[] => {
29	      const options =
30	        kind === 'find'
31	          ? serverConfig.kialiFeatureFlags.uiDefaults.mesh.findOptions
32	          : serverConfig.kialiFeatureFlags.uiDefaults.mesh.hideOptions;
33	      return options.map(o => {
34	        return (
35	          <DropdownItem key={o.description} onClick={() => onSelect(o.expression)}>
36	            {o.description}
37	          </DropdownItem>
38	        );
39	      });
40	    };
41	
42	    setOptions(getOptionItems(kind));
43	  }, [kind, onSelect]);
44	
45	  const onToggle = (isOpen: boolean) => {
46	    setIsOpen(isOpen);
47	  };
48	
49	  return (
50	    <Dropdown
51	      key={`mesh-${kind}-presets`}
52	      id={`mesh-${kind}-presets`}
53	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
54	        <MenuToggle
55	          ref={toggleRef}
56	          className={menuToggleStyle}
57	          data-test={`${kind}-options-dropdown`}
58	          onClick={() => onToggle(!isOpen)}
59	          isExpanded={isOpen}
60	        />
61	      )}
62	      isOpen={isOpen}
63	      onOpenChange={(isOpen: boolean) => onToggle(isOpen)}
64	      popperProps={{ position: 'right' }}
65	    >
66	      <DropdownList>{options}</DropdownList>
67	    </Dropdown>
68	  );
69	};

